//! Vendor SDK loader infrastructure.
//!
//! Every vendor SDK wrapper has the same boilerplate:
//!
//! 1. A list of candidate library paths to search (vendor install dirs, system
//!    library paths, executable-relative locations).
//! 2. `libloading::Library::new(path)` until one succeeds.
//! 3. `Library::get::<fn>(b"SymbolName\0")` for each required symbol, stored as
//!    function pointers in a struct.
//! 4. A `OnceLock<Option<Self>>` singleton with a `get() -> Option<&'static Self>`
//!    accessor.
//!
//! Across 13 vendors that ~500-line block was copy-pasted 13 times. This module
//! centralizes the path search and symbol resolution, exposes a typed error
//! channel (`VendorLoadError`), and provides the [`load_vendor_sdk!`] macro that
//! generates the whole struct/static/impl group from a single declarative entry.
//!
//! # Why a macro and not just a trait
//!
//! Each vendor's function-pointer table has unique extern "C" signatures (different
//! parameter counts and types). A trait alone cannot express "give me a struct
//! whose fields are these specific `unsafe extern "C" fn(...)` types" without
//! significant generic gymnastics. The macro does the trivial code generation
//! (struct + impl) while delegating path search and library opening to the
//! runtime helper [`open_vendor_library`].
//!
//! # Migration pattern (for the remaining 12 vendors)
//!
//! Replace the per-vendor `struct XyzSdk { ... }`, `static XYZ_SDK`, and
//! `impl XyzSdk { fn load() ... fn get() ... }` blocks with a single
//! `load_vendor_sdk!` invocation. The macro generates the same public surface
//! (`XyzSdk::get() -> Option<&'static XyzSdk>` and per-field `unsafe extern "C" fn`
//! function pointers), so call sites at the use site (e.g.
//! `unsafe { (sdk.start_exposure)(...) }`) do not change.
//!
//! See `zwo.rs` for the canonical example covering all three SDK loaders
//! (`AsiSdk`, `EafSdk`, `EfwSdk`).
//!
//! Remaining vendors (effort estimates documented in
//! `docs/plans/2026-05-10-vendor-sdk-migration.md`):
//! atik, fli, fujifilm, gphoto2, ioptron, lx200, moravian, player_one, qhy,
//! skywatcher, svbony, touptek.

use std::path::PathBuf;
use thiserror::Error;

/// Errors that can occur while locating and loading a vendor SDK shared library.
///
/// Each variant is mapped to a distinct failure mode so callers can decide whether
/// to log at `debug` (expected absence — driver simply unavailable on this host),
/// `warn` (library present but corrupt), or `error` (library present but missing
/// a documented symbol — likely a version mismatch the user should know about).
#[derive(Debug, Error)]
pub enum VendorLoadError {
    /// None of the candidate library paths exist or were openable. This is the
    /// expected outcome on machines that simply don't have the vendor SDK
    /// installed and should be logged at `debug` level.
    #[error(
        "{vendor}: none of {candidates_tried} candidate library paths could be opened; last error: {last_error}"
    )]
    PathNotFound {
        vendor: &'static str,
        candidates_tried: usize,
        last_error: String,
    },

    /// A library was found and `libloading::Library::new` succeeded, but a
    /// required symbol could not be resolved. This indicates a version
    /// mismatch — the library is present but does not expose the API the
    /// driver expects. Always logged at `error` level so the user can update.
    #[error("{vendor}: failed to resolve symbol '{symbol}' from '{library_path}': {source}")]
    SymbolNotFound {
        vendor: &'static str,
        symbol: &'static str,
        library_path: String,
        source: libloading::Error,
    },

    /// A library file existed on disk but `libloading::Library::new` rejected
    /// it (corrupt file, ABI mismatch, missing transitive dependency).
    #[error("{vendor}: library at '{library_path}' could not be opened: {source}")]
    LibraryOpenFailed {
        vendor: &'static str,
        library_path: String,
        source: libloading::Error,
    },
}

/// Metadata describing a vendor SDK. Implementors are typically generated by the
/// [`load_vendor_sdk!`] macro, not written by hand. The trait exists so future
/// tooling (e.g. a CLI that lists "which SDKs would be loaded on this host?") has
/// a uniform introspection point.
pub trait VendorSdk: Sized + Send + Sync + 'static {
    /// Human-readable vendor SDK name, used in log messages and error payloads.
    /// Examples: "ZWO ASI Camera", "ZWO EAF Focuser", "QHY Camera".
    fn name() -> &'static str;

    /// Ordered list of candidate library paths to try. The first one that
    /// opens successfully wins. Per-platform paths should already be filtered
    /// (i.e. only return `.dll` paths on Windows, `.so` on Linux, `.dylib` on
    /// macOS); the loader does not filter by extension.
    fn candidate_library_paths() -> Vec<PathBuf>;

    /// Required C symbol names. Used purely for introspection and diagnostics —
    /// the macro generates the actual `Library::get` calls inline because each
    /// symbol's `unsafe extern "C" fn(...)` signature is unique per vendor.
    fn required_symbols() -> &'static [&'static str];
}

/// Walk `candidate_paths` and return the first library that loads, along with
/// the path that produced it (for logging).
///
/// This is the runtime workhorse the [`load_vendor_sdk!`] macro calls before
/// resolving symbols. It is exposed publicly so vendors with unusual loading
/// semantics (e.g. Touptek's multi-brand storage that needs custom `OnceLock`
/// keying) can compose path search separately from symbol resolution.
pub fn open_vendor_library(
    vendor: &'static str,
    candidate_paths: &[PathBuf],
) -> Result<(libloading::Library, PathBuf), VendorLoadError> {
    let mut last_error: Option<libloading::Error> = None;

    for path in candidate_paths {
        tracing::debug!("{}: trying to load SDK from {}", vendor, path.display());
        // SAFETY: libloading::Library::new is unsafe because loading a foreign
        // library executes arbitrary initialization code from that library. We
        // accept that risk; this is how every vendor SDK is loaded.
        match unsafe { libloading::Library::new(path) } {
            Ok(lib) => {
                tracing::info!("{}: loaded SDK from {}", vendor, path.display());
                return Ok((lib, path.clone()));
            }
            Err(e) => {
                tracing::debug!(
                    "{}: load attempt at {} failed: {}",
                    vendor,
                    path.display(),
                    e
                );
                last_error = Some(e);
            }
        }
    }

    Err(VendorLoadError::PathNotFound {
        vendor,
        candidates_tried: candidate_paths.len(),
        last_error: last_error
            .map(|e| e.to_string())
            .unwrap_or_else(|| "no candidate paths supplied".to_string()),
    })
}

/// Resolve a single symbol from an already-opened library. Wraps
/// `libloading::Library::get` with the project's typed error variant so symbol
/// failures carry the vendor + library path + symbol name in their error
/// payload.
///
/// `symbol_name_with_nul` MUST be NUL-terminated (e.g. `b"ASIGetNumOfConnectedCameras\0"`)
/// because that is what `libloading::Library::get` expects. `symbol_name_for_log`
/// is the same name without the NUL byte, for diagnostics.
///
/// # Safety
///
/// The caller must ensure `T` exactly matches the foreign function's ABI and
/// signature. Mismatched signatures invoke undefined behavior on call.
pub unsafe fn resolve_symbol<T: Copy>(
    vendor: &'static str,
    library: &libloading::Library,
    library_path: &std::path::Path,
    symbol_name_with_nul: &[u8],
    symbol_name_for_log: &'static str,
) -> Result<T, VendorLoadError> {
    match library.get::<T>(symbol_name_with_nul) {
        Ok(sym) => Ok(*sym),
        Err(e) => {
            tracing::error!(
                "{}: failed to resolve required symbol '{}' from '{}': {}",
                vendor,
                symbol_name_for_log,
                library_path.display(),
                e
            );
            Err(VendorLoadError::SymbolNotFound {
                vendor,
                symbol: symbol_name_for_log,
                library_path: library_path.display().to_string(),
                source: e,
            })
        }
    }
}

/// Declarative SDK loader generator.
///
/// Generates the per-vendor SDK struct (function-pointer table), a
/// `OnceLock<Option<Self>>` singleton, and `impl Sdk { fn get() -> Option<&'static Self> }`
/// from a single declarative block. Public API matches the hand-written
/// pattern that preceded it so call sites do not change.
///
/// # Example
///
/// ```ignore
/// load_vendor_sdk! {
///     /// ZWO ASI Camera SDK
///     vendor_name: "ZWO ASI Camera",
///     sdk_struct: AsiSdk,
///     sdk_static: ASI_SDK,
///     // Each platform's candidate library paths. The macro evaluates the
///     // expression at call time so dynamic paths (e.g. exe-relative) work.
///     candidate_paths_fn: collect_asi_candidate_paths,
///     symbols: {
///         get_num_cameras: b"ASIGetNumOfConnectedCameras\0"
///             => unsafe extern "C" fn() -> std::ffi::c_int,
///         open_camera: b"ASIOpenCamera\0"
///             => unsafe extern "C" fn(std::ffi::c_int) -> std::ffi::c_int,
///     }
/// }
/// ```
///
/// The macro generates roughly:
///
/// ```ignore
/// struct AsiSdk {
///     get_num_cameras: unsafe extern "C" fn() -> c_int,
///     open_camera: unsafe extern "C" fn(c_int) -> c_int,
///     _library: libloading::Library,
/// }
/// static ASI_SDK: std::sync::OnceLock<Option<AsiSdk>> = std::sync::OnceLock::new();
/// impl AsiSdk {
///     fn load() -> Option<Self> { ... open library, resolve symbols ... }
///     pub fn get() -> Option<&'static AsiSdk> { ASI_SDK.get_or_init(Self::load).as_ref() }
///     pub fn required_symbol_names() -> &'static [&'static str] { ... }
/// }
/// impl crate::vendor::sdk_loader::VendorSdk for AsiSdk { ... }
/// ```
///
/// Symbol resolution errors are logged at `error` level (see
/// [`resolve_symbol`]); the function returns `None` so call sites can treat
/// "SDK absent" and "SDK present but symbol missing" the same way (driver
/// simply unavailable). Detailed diagnostics are emitted via `tracing`.
#[macro_export]
macro_rules! load_vendor_sdk {
    (
        $(#[$sdk_meta:meta])*
        vendor_name: $vendor_name:expr,
        sdk_struct: $sdk:ident,
        sdk_static: $sdk_static:ident,
        candidate_paths_fn: $paths_fn:path,
        symbols: {
            $(
                $field:ident : $sym_bytes:expr
                    => unsafe extern $abi:literal fn ( $($arg_ty:ty),* $(,)? ) $(-> $ret_ty:ty)?
            ),* $(,)?
        }
        $(,)?
    ) => {
        $(#[$sdk_meta])*
        struct $sdk {
            $(
                $field: unsafe extern $abi fn ( $($arg_ty),* ) $(-> $ret_ty)?,
            )*
            #[allow(dead_code)]
            _library: libloading::Library,
        }

        static $sdk_static: std::sync::OnceLock<Option<$sdk>> = std::sync::OnceLock::new();

        impl $sdk {
            fn load() -> Option<Self> {
                let candidate_paths: Vec<std::path::PathBuf> = $paths_fn();

                let (library, library_path) =
                    match $crate::vendor::sdk_loader::open_vendor_library(
                        $vendor_name,
                        &candidate_paths,
                    ) {
                        Ok(pair) => pair,
                        Err(e) => {
                            // Path-not-found is the expected case on hosts
                            // that don't have the SDK installed; debug-level
                            // logging avoids spamming the user log.
                            tracing::debug!("{}: SDK unavailable: {}", $vendor_name, e);
                            return None;
                        }
                    };

                // SAFETY: each symbol's signature is supplied by the macro
                // caller and must match the foreign function's ABI; the macro
                // forwards the burden to the declaration site.
                //
                // The `#[allow(clippy::macro_metavars_in_unsafe)]` is required
                // because `$arg_ty`/`$ret_ty` are interpolated inside an
                // `unsafe { ... }` block; this is intentional — `resolve_symbol`
                // is unsafe and the signature is part of the unsafe call.
                #[allow(clippy::macro_metavars_in_unsafe)]
                let result = (|| -> Result<Self, $crate::vendor::sdk_loader::VendorLoadError> {
                    Ok(Self {
                        $(
                            // SAFETY: `resolve_symbol::<F>` is `unsafe` because
                            // the caller asserts that the symbol's ABI matches
                            // the supplied `F = unsafe extern $abi fn (...)`.
                            // The macro caller (vendor SDK declaration site —
                            // e.g. zwo.rs, fli.rs) hand-derives each signature
                            // from the vendor C header, and any mismatch will
                            // fail at the first FFI call. `library` outlives the
                            // returned function pointer because it is stored in
                            // the same `Self { _library: library }` struct that
                            // owns the resolved symbol.
                            $field: unsafe {
                                $crate::vendor::sdk_loader::resolve_symbol::<
                                    unsafe extern $abi fn ( $($arg_ty),* ) $(-> $ret_ty)?
                                >(
                                    $vendor_name,
                                    &library,
                                    &library_path,
                                    $sym_bytes,
                                    stringify!($field),
                                )?
                            },
                        )*
                        _library: library,
                    })
                })();

                match result {
                    Ok(sdk) => {
                        tracing::info!(
                            "{}: all required symbols resolved",
                            $vendor_name
                        );
                        Some(sdk)
                    }
                    Err(e) => {
                        // resolve_symbol already logged at error level; surface
                        // here as None so callers see "SDK unavailable".
                        tracing::error!(
                            "{}: SDK present but symbol resolution failed: {}",
                            $vendor_name,
                            e
                        );
                        None
                    }
                }
            }

            /// Public accessor for the lazy-initialized SDK singleton.
            ///
            /// Returns `Some(&Self)` if the SDK loaded successfully, `None`
            /// otherwise. The first call triggers `load()`; subsequent calls
            /// are O(1).
            pub fn get() -> Option<&'static Self> {
                $sdk_static.get_or_init(Self::load).as_ref()
            }

            /// List of C symbol names this SDK requires. Returned in the order
            /// they are declared in the `load_vendor_sdk!` invocation. Useful
            /// for diagnostic tooling.
            pub fn required_symbol_names() -> &'static [&'static str] {
                &[$( stringify!($field) ),*]
            }
        }

        impl $crate::vendor::sdk_loader::VendorSdk for $sdk {
            fn name() -> &'static str {
                $vendor_name
            }

            fn candidate_library_paths() -> Vec<std::path::PathBuf> {
                $paths_fn()
            }

            fn required_symbols() -> &'static [&'static str] {
                Self::required_symbol_names()
            }
        }
    };
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn open_vendor_library_returns_path_not_found_when_all_candidates_fail() {
        // Use paths that definitely do not exist on any host.
        let candidates = vec![
            PathBuf::from("/nonexistent/path/foo.so"),
            PathBuf::from("/nonexistent/path/bar.dll"),
        ];
        let err = open_vendor_library("TestVendor", &candidates).expect_err("must fail");
        match err {
            VendorLoadError::PathNotFound {
                vendor,
                candidates_tried,
                ..
            } => {
                assert_eq!(vendor, "TestVendor");
                assert_eq!(candidates_tried, 2);
            }
            other => panic!("expected PathNotFound, got {:?}", other),
        }
    }

    #[test]
    fn open_vendor_library_returns_path_not_found_with_empty_candidate_list() {
        let err = open_vendor_library("TestVendor", &[]).expect_err("must fail");
        match err {
            VendorLoadError::PathNotFound {
                candidates_tried, ..
            } => {
                assert_eq!(candidates_tried, 0);
            }
            other => panic!("expected PathNotFound, got {:?}", other),
        }
    }
}
